const RegistrationProgress: React.FC<RegistrationProgressProps> = ({ currentStep }) => {
  const steps = [
    { label: 'Negócio', icon: <Building2 size={20} /> },
    { label: 'Tipos', icon: <Tag size={20} /> },
    { label: 'Trabalho', icon: <Briefcase size={20} /> },
