              {step.icon}
            </div>
            <span className={`text-[10px] font-bold uppercase tracking-wider ${isActive ? 'text-gray-900' : 'text-gray-400'}`}>
              {step.label}
            </span>
          </div>
        );
      })}
    </div>
  );
};

